// ParseDayDuration accepts the Go-stdlib duration syntax (`168h`, `30m`,
// `1h30m`, `500ms`) plus a day suffix (`7d`, `30d`) that `time.ParseDuration`
// rejects with `unknown unit "d"`. Use this on any user-facing duration flag
// whose values are likely to be expressed in days — windowed reports,
// "stale" thresholds, "since" filters. `printing-press dogfood`'s test
// matrix synthesizes `7d` / `30d` as fixture inputs for duration flags,
// so commands that don't honor the day suffix fail Phase 5 verification.
//
// Compound forms that combine days with other units (`1d6h`) are
// intentionally not supported — the present pattern is a single
// magnitude per flag; mixing units invites ambiguity (when does the
// day boundary start?).
func ParseDayDuration(s string) (time.Duration, error) {
	s = strings.TrimSpace(s)
	if s == "" {
		return 0, fmt.Errorf("empty duration")
	}
	// Bare "Nd" form. Pass anything else through to time.ParseDuration so
	// stdlib-shaped values (h, m, s, ms, us, ns and combinations) still
	// parse normally.
	if strings.HasSuffix(s, "d") && !strings.ContainsAny(s, "hms") {
		n, err := strconv.Atoi(s[:len(s)-1])
		if err == nil {
			return time.Duration(n) * 24 * time.Hour, nil
		}
	}
	return time.ParseDuration(s)
}
